def find_zero(xs: list):
    """ xs are coefficients of a polynomial.
    find_zero find x such that poly(x) = 0.
    find_zero returns only only zero point, even if there are many.
    Moreover, find_zero only takes list xs having even number of coefficients
    and largest non zero coefficient as it guarantees
    a solution.
    """
    def poly(x, xs):
        return sum([coeff * math.pow(x, i) for i, coeff in enumerate(xs)])

    if len(xs) % 2 != 0:
        raise ValueError("List of coefficients must have even length")

    if xs[-1] == 0:
        raise ValueError("Largest non-zero coefficient must be non-zero")

    # Use the Newton-Raphson method to find the root
    x = -xs[0] / xs[1]
    for _ in range(100):
        f = poly(x, xs)
        if abs(f) < 1e-10:
            break
        df = sum([coeff * i * math.pow(x, i-1) for i, coeff in enumerate(xs[1:])])
        if df == 0:
            raise ZeroDivisionError("Derivative is zero, no solution found")
        x = x - f / df

    return x

